module dram_cell(  
    input clk,  
    input wr_en,  
    input [15:0] data_in,  
    output reg [15:0] data_out  
);  
    reg [15:0] memory;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (wr_en) begin  
            memory <= data_in;  
        end  
        data_out <= memory;  
    end  
endmodule
